mapper.select:
SELECT u.*
FROM sys_user u
WHERE u.username = #{username}

  AND (
      u.tenant_id = #{tenantId}
      OR EXISTS (
          SELECT 1
          FROM sys_user_tenant sut
          WHERE sut.user_id = u.id
            AND sut.tenant_id = #{tenantId}
            AND sut.status = 1
      )
  )



        ORDER BY CASE WHEN u.tenant_id = #{tenantId} THEN 0 ELSE 1 END, u.id ASC


        ORDER BY CASE WHEN u.tenant_id = 1 THEN 0 ELSE 1 END, u.id ASC


LIMIT 1

